const express = require('express');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

// PostgreSQL connection settings
const dbConfig = {
  user: 'postgres',
  host: 'localhost',
  database: 'mydatabase',
  password: 'mypassword',
  port: 5432,
};

// Create a pool of connections to the database
const pool = new Pool(dbConfig);

// Function to create a new record in the users table
async function createUser(req, res) {
  try {
    const result = await pool.query(
      `INSERT INTO users (name, email, password)
       VALUES ($1, $2, $3) RETURNING *`,
      [req.body.name, req.body.email, req.body.password]
    );
    res.json(result.rows[0]);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error creating user' });
  }
}

// Function to read all records from the users table
async function getUsers(req, res) {
  try {
    const result = await pool.query('SELECT * FROM users');
    res.json(result.rows);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error fetching users' });
  }
}

// Function to update a record in the users table
async function updateUser(req, res) {
  try {
    const id = req.params.id;
    const result = await pool.query(
      `UPDATE users SET name=$1, email=$2, password=$3 WHERE id=$4 RETURNING *`,
      [req.body.name, req.body.email, req.body.password, id]
    );
    res.json(result.rows[0]);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error updating user' });
  }
}

// Function to delete a record from the users table
async function deleteUser(req, res) {
  try {
    const id = req.params.id;
    await pool.query(`DELETE FROM users WHERE id=$1`, [id]);
    res.json({ message: `User ${id} deleted` });
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error deleting user' });
  }
}

// API endpoints
app.post('/users', createUser);
app.get('/users', getUsers);
app.put('/users/:id', updateUser);
app.delete('/users/:id', deleteUser);

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});